# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(transactions, account_balances):
    """
    Process financial transactions and update account balances.
    
    Args:
        transactions (list): List of transaction dictionaries with keys 'account_id', 'amount', 'type'
        account_balances (dict): Dictionary with account_ids as keys and current balances as values
    
    Returns:
        dict: Updated account balances
    """
    # Create a copy of the balances to avoid modifying the original
    updated_balances = account_balances.copy()
    
    # Process each transaction
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        transaction_type = transaction['type']  # 'credit' or 'debit'
        
        # Initialize account balance if it doesn't exist
        if account_id not in updated_balances:
            updated_balances[account_id] = 0
        
        # Update balance based on transaction type
        if transaction_type == 'credit':
            updated_balances[account_id] += amount
        elif transaction_type == 'debit':
            updated_balances[account_id] -= amount
    
    return updated_balances